  if(featured||free)Object.assign(patch,{featuredOnHome:true,isFeatured:true,homeFeatured:true,visibleOnHome:true,isFree:true,planId:'free',featuredAt:TS(),featuredBy:actor?.uid||'system',featuredSource:actor?'admin_click':'system_repair',homePriority:Date.now(),homePinned:featured===true});
  const batch=db.batch();batch.set(ref,patch,{merge:true});
