  await batch.commit();
  const after={...before,...patch,id:surveyId};
  const slug=company.slug||company.publicSlug||'valora-group';
  const publicUrl=buildPublicSurveyUrl({id:surveyId},company,tokenValue);
  if(forbiddenPublicUrl(publicUrl))throw demoBlockError('public_url_invalid','URL pública inválida para produção.',{surveyId,url:publicUrl});
  const safeForm=sanitizePublicFormForClient(form), safeCompany=sanitizePublicCompanyForClient(company);
  return {ok:true,source:'prepared_public_survey',surveyId,url:publicUrl,token:tokenValue,org:slug,otherFeaturedDisabled,survey:{id:surveyId,title:after.title||'',formId:before.formId,companyId,organizationId:before.organizationId||companyId,status:'published',visibility:'public',featuredOnHome:patch.featuredOnHome===true,isFeatured:patch.isFeatured===true,homeFeatured:patch.homeFeatured===true,visibleOnHome:patch.visibleOnHome===true,isFree:patch.isFree===true,planId:patch.planId||'',hasPublicToken:true,hasTokenHash:true,tokenEqualsHash:false},form:safeForm,company:safeCompany,consistency:{surveyIdMatchesRequest:true,selectedSurveyId:surveyId,selectedSurveyTitle:after.title||'',surveyFormId:before.formId,returnedFormId:safeForm.id,companyId,companySlug:slug,formMatchesSurvey:safeForm.id===before.formId,urlSurveyId:surveyId,blockedDemo:false,source:'prepared_public_survey'}};
