async function purgeProductionDemoDataInternal({dryRun=true,apply=false}={}){
  const collections=['surveys','forms','organizations','companies','invitations','responses'];
  const report={ok:true,dryRun:dryRun!==false,apply:apply===true,matched:{surveys:[],forms:[],companies:[],organizations:[],invitations:[],responses:[]},actions:[],totals:{surveys:0,forms:0,companies:0,organizations:0,invitations:0,responses:0},demoUrlsFound:[]};
  const batch=db.batch();let writes=0;
  const addWrite=(ref,patch,action)=>{report.actions.push(action);if(report.dryRun||!report.apply)return;batch.set(ref,patch,{merge:true});writes++;};
  for(const name of collections){
    const snap=await db.collection(name).get();
    for(const doc of snap.docs){
      const row={id:doc.id,...doc.data()};
      [row.publicUrl,row.publicLink,row.url,row.link,row.shareUrl].filter(Boolean).map(String).filter(forbiddenPublicUrl).forEach(url=>report.demoUrlsFound.push({collection:name,id:doc.id,url:'[blocked-demo-url]'}));
      if(!isDemoRecord(row))continue;
      const bucket=report.matched[name]||report.matched[`${name}s`]; if(bucket)bucket.push(doc.id); if(report.totals[name]!==undefined)report.totals[name]++;
      if(name==='responses')continue;
      if(name==='surveys')addWrite(doc.ref,demoArchivePatch(true),{collection:name,id:doc.id,action:'archive_revoke_hide_survey'});
      else if(name==='forms')addWrite(doc.ref,demoArchivePatch(false),{collection:name,id:doc.id,action:'archive_form'});
      else if(name==='organizations'||name==='companies')addWrite(doc.ref,demoArchivePatch(false),{collection:name,id:doc.id,action:'archive_org_company'});
      else if(name==='invitations')addWrite(doc.ref,{status:'revoked',revoked:true,deleted:true,updatedAt:TS()},{collection:name,id:doc.id,action:'revoke_invitation'});
    }
  }
  if(writes)await batch.commit();
  return report;
}
