exports.getEmailJobStatus=onCall(async req=>{const user=await authedUser(req);if(user.role!=='admin_valora')throw new HttpsError('permission-denied','Apenas admin_valora.');const id=required(req.data,'id');const snap=await db.collection('emailJobs').doc(id).get();if(!snap.exists)throw new HttpsError('not-found','Email job não encontrado.');const d=snap.data();return {id:snap.id,status:d.status,attempts:d.attempts,maxAttempts:d.maxAttempts,responseId:d.responseId,participantEmailMasked:d.participantEmailMasked};});
exports.scheduledProcessEmailRetries=onSchedule({schedule:'every 30 minutes',secrets:[SMTP_PASSWORD]},async()=>{const qs=await db.collection('emailJobs').where('status','==','pending_retry').where('nextAttemptAt','<=',admin.firestore.Timestamp.now()).limit(10).get();for(const doc of qs.docs){try{await processEmailJobDocument(doc.ref,{uid:'system',role:'system'});}catch(err){console.error('scheduled email retry sanitized error',cleanText(err.message,240));}}});
exports.repairFreeSurveyPublicLink=onCall(async req=>{const user=await authedUser(req);if(user.role!=='admin_valora')throw new HttpsError('permission-denied','Apenas admin_valora.');const surveyId=required(req.data,'surveyId');const ref=db.collection('surveys').doc(surveyId);const snap=await ref.get();if(!snap.exists)throw new HttpsError('not-found','Pesquisa não encontrada.');const before={id:snap.id,...snap.data()};let tokenValue=publicToken(before);if(!tokenValue)tokenValue=createToken(24);const patch={publicToken:tokenValue,token:tokenValue,tokenHash:sha256(tokenValue),publicUrl:`/survey/${surveyId}?token=${tokenValue}`,publicLink:`/survey/${surveyId}?token=${tokenValue}`,visibility:'public',isFree:true,planId:'free',showResult:true,allowRepeat:true,revoked:false,revokedAt:null,visibleOnHome:true,featuredOnHome:true,isFeatured:true,homeFeatured:true,status:['active','published','open'].includes(String(before.status||'').toLowerCase())?before.status:'published',expiresAt:before.expiresAt||admin.firestore.Timestamp.fromDate(new Date('2099-12-31T23:59:59Z')),updatedAt:TS(),repairedBy:user.uid};await ref.set(patch,{merge:true});await auditLog(db,{action:'repairFreeSurveyPublicLink',actorId:user.uid,actorType:user.role,entity:'survey',entityId:surveyId,after:{beforeStatus:before.status,status:patch.status,publicToken:maskSensitiveToken(tokenValue),visibility:'public',isFree:true}});return {repaired:true,survey:{id:surveyId,featuredOnHome:true,isFeatured:true,homeFeatured:true,visibleOnHome:true,isFree:true,planId:'free',visibility:'public',status:patch.status,showResult:true,allowRepeat:true,revoked:false,hasPublicToken:true,tokenMasked:maskSensitiveToken(tokenValue)}};});

const ADMIN_CRUD_ROLES=new Set(['admin_valora','consultor_valora','empresa_admin','gestor_pesquisa']);
const GLOBAL_ADMIN_ROLES=new Set(['admin_valora','consultor_valora']);
const PRIVATE_FIRESTORE_KEYS=new Set(['__collection','__dirty','__temp','_ui','_local','_editing','_selected','_expanded','_cache','_diagnostics']);
function deepCleanForFirestore(value,seen=new WeakSet()){
  if(value===undefined||typeof value==='function')return undefined;
  if(value===null||typeof value!=='object')return value;
  if(value instanceof Date)return value;
  if(value&&typeof value.toDate==='function'&&typeof value.seconds==='number')return value;
  if(seen.has(value))return undefined;seen.add(value);
  if(Array.isArray(value))return value.map(v=>deepCleanForFirestore(v,seen)).filter(v=>v!==undefined);
  const out={};
  Object.keys(value).forEach(k=>{if(PRIVATE_FIRESTORE_KEYS.has(k))return;const v=deepCleanForFirestore(value[k],seen);if(v!==undefined)out[k]=v;});
  return out;
}
function adminCrudError(status,message,code,extra={}){return new HttpsError(status,message,{code,...extra});}
function formIdFromData(data={}){return cleanText(data?.id||data?.formId||'',160);}
function surveyIdFromData(data={}){return cleanText(data?.surveyId||data?.id||'',160);}
async function adminCrudUser(req){const user=await authedUser(req);if(!ADMIN_CRUD_ROLES.has(user.role))throw adminCrudError('permission-denied','Sem permissão administrativa para esta operação.','admin_crud_role_required');return user;}
function assertCompanyScope(user,doc={}){const cid=doc.companyId||doc.organizationId||'';if(!GLOBAL_ADMIN_ROLES.has(user.role)&&cid&&cid!==user.companyId)throw adminCrudError('permission-denied','Registro fora do escopo da sua empresa.','company_scope_denied',{companyId:cid});}
async function safeAudit(entry){try{await auditLog(db,entry);}catch(err){console.warn('[adminCrud] audit non-blocking',err?.message||err);}}
async function countResponsesForSurvey(surveyId){const q=await db.collection('responses').where('surveyId','==',surveyId).get();return q.size;}
async function surveysForForm(formId){const q=await db.collection('surveys').where('formId','==',formId).get();return q.docs.map(d=>({id:d.id,...d.data()}));}
async function responsesForSurveys(ids=[]){if(!ids.length)return 0;let total=0;for(const id of ids)total+=await countResponsesForSurvey(id);return total;}
const ACTIVE_SURVEY_STATUSES=new Set(['active','published','open']);
const CLOSED_SURVEY_STATUSES=new Set(['closed','ended','inactive']);
function surveyUsageRow(s,responseCount=0){return deepCleanForFirestore({id:s.id,title:s.title||s.name||'Pesquisa sem título',status:s.status||'',visibility:s.visibility||'',responseCount:Number(s.responseCount||responseCount||0),featuredOnHome:s.featuredOnHome===true,isFeatured:s.isFeatured===true,createdAt:s.createdAt||null,updatedAt:s.updatedAt||null});}
async function buildFormUsage(formId,form={}){const surveys=await surveysForForm(formId);let responsesCount=0;const rows=[];for(const s of surveys){const rc=Number(s.responseCount||0)||await countResponsesForSurvey(s.id);responsesCount+=rc;rows.push(surveyUsageRow(s,rc));}
  const activeSurveys=rows.filter(s=>ACTIVE_SURVEY_STATUSES.has(String(s.status||'').toLowerCase())&&!surveys.find(x=>x.id===s.id)?.deleted);
  const closedSurveys=rows.filter(s=>CLOSED_SURVEY_STATUSES.has(String(s.status||'').toLowerCase()));
  const archivedSurveys=rows.filter(s=>String(s.status||'').toLowerCase()==='archived'||surveys.find(x=>x.id===s.id)?.deleted===true);
  return {activeSurveys,closedSurveys,archivedSurveys,responsesCount,activeSurveysCount:activeSurveys.length,totalSurveysCount:surveys.length,canEditText:true,canDelete:surveys.length===0&&responsesCount===0,canArchive:surveys.length>0||responsesCount>0,requiresVersioning:responsesCount>0};}
function surveyPatchFromPayload(data,current={}){const allowed=['title','description','status','startsAt','expiresAt','visibility','featuredOnHome','isFeatured','homeFeatured','visibleOnHome','isFree','planId','requireIdentification','lgpdRequired','allowRepeat','showResult','anonymous','formId'];const out={};allowed.forEach(k=>{if(Object.prototype.hasOwnProperty.call(data,k))out[k]=data[k];});['id','createdAt','createdBy','companyId','organizationId','publicToken','token','tokenHash','responseCount','resultCount'].forEach(k=>{if(current[k]!==undefined&&out[k]===undefined)out[k]=current[k];});out.updatedAt=TS();return deepCleanForFirestore(out);}
function hasBreakingFormChange(oldForm={},nextForm={}){const oldQs=new Map((oldForm.questions||[]).map(q=>[q.id,q]));const nextQs=new Map((nextForm.questions||oldForm.questions||[]).map(q=>[q.id,q]));for(const [id,q] of oldQs){const n=nextQs.get(id);if(!n)return {breaking:true,reason:'question_removed'};if(n.type&&q.type&&n.type!==q.type)return {breaking:true,reason:'question_type_changed'};const oldOpts=new Set((q.options||[]).map(o=>o.id).filter(Boolean));const nextOpts=new Set((n.options||[]).map(o=>o.id).filter(Boolean));for(const opt of oldOpts)if(!nextOpts.has(opt))return {breaking:true,reason:'option_removed'};}return {breaking:false};}
function formVersionId(base,version){return `${String(base||'form').replace(/_v\d+$/,'')}_v${version}`;}

exports.adminGetFormUsage=onCall(async req=>{const user=await adminCrudUser(req), formId=formIdFromData(req.data);if(!formId)throw adminCrudError('invalid-argument','ID do formulário obrigatório.','form_id_required');const snap=await db.collection('forms').doc(formId).get();if(!snap.exists)throw adminCrudError('not-found','Formulário não encontrado.','form_not_found');const form={id:snap.id,...snap.data()};assertCompanyScope(user,form);const usage=await buildFormUsage(formId,form);return deepCleanForFirestore({ok:true,formId,form,usage});});
exports.adminCloseSurveysByForm=onCall(async req=>{const user=await adminCrudUser(req), formId=formIdFromData(req.data), mode=String(req.data?.mode||'close');if(!formId)throw adminCrudError('invalid-argument','ID do formulário obrigatório.','form_id_required');if(!['close','archive'].includes(mode))throw adminCrudError('invalid-argument','Modo inválido.','invalid_close_mode');const formSnap=await db.collection('forms').doc(formId).get();if(!formSnap.exists)throw adminCrudError('not-found','Formulário não encontrado.','form_not_found');const form={id:formSnap.id,...formSnap.data()};assertCompanyScope(user,form);const surveys=(await surveysForForm(formId)).filter(s=>ACTIVE_SURVEY_STATUSES.has(String(s.status||'').toLowerCase())&&!s.deleted);const affected=[];const batch=db.batch();for(const s of surveys){assertCompanyScope(user,s);const patch=deepCleanForFirestore(mode==='archive'?{status:'archived',archived:true,archivedAt:TS(),archivedBy:user.uid,visibility:'private',featuredOnHome:false,isFeatured:false,homeFeatured:false,visibleOnHome:false,revoked:true,revokedAt:TS(),updatedAt:TS(),updatedBy:user.uid}:{status:'closed',closedAt:TS(),closedBy:user.uid,visibility:'private',featuredOnHome:false,isFeatured:false,homeFeatured:false,visibleOnHome:false,revoked:true,revokedAt:TS(),updatedAt:TS(),updatedBy:user.uid});batch.set(db.collection('surveys').doc(s.id),patch,{merge:true});affected.push(surveyUsageRow({...s,...patch},Number(s.responseCount||0)));}await batch.commit();await safeAudit({action:'adminCloseSurveysByForm',actorId:user.uid,actorType:user.role,companyId:form.companyId,entity:'form',entityId:formId,after:{mode,count:affected.length}});return {ok:true,formId,affectedSurveysCount:affected.length,affectedSurveys:affected};});
exports.adminCreateSurvey=onCall(async req=>{const user=await adminCrudUser(req), data=deepCleanForFirestore(asObject(req.data?.payload||{},'payload'));assertCompanyScope(user,data);const ref=data.id?db.collection('surveys').doc(data.id):db.collection('surveys').doc();const payload=deepCleanForFirestore({...data,id:ref.id,companyId:data.companyId||user.companyId,organizationId:data.organizationId||data.companyId||user.companyId,createdAt:TS(),updatedAt:TS(),createdBy:user.uid,updatedBy:user.uid});await ref.set(payload,{merge:false});await safeAudit({action:'adminCreateSurvey',actorId:user.uid,actorType:user.role,companyId:payload.companyId,entity:'survey',entityId:ref.id,after:{title:payload.title}});return {ok:true,id:ref.id,survey:payload};});
exports.adminUpdateSurvey=onCall(async req=>{const user=await adminCrudUser(req), id=surveyIdFromData(req.data);if(!id)throw adminCrudError('invalid-argument','ID da pesquisa obrigatório.','survey_id_required');const data=deepCleanForFirestore(asObject(req.data?.payload||{},'payload'));const ref=db.collection('surveys').doc(id);const snap=await ref.get();if(!snap.exists)throw adminCrudError('not-found','Pesquisa não encontrada.','survey_not_found');const current={id:snap.id,...snap.data()};assertCompanyScope(user,current);if(data.formId&&data.formId!==current.formId&&(current.responseCount>0||await countResponsesForSurvey(id)>0))throw adminCrudError('failed-precondition','Esta pesquisa já possui respostas. Crie uma nova pesquisa para trocar o formulário.','survey_has_responses_form_change_blocked');const patch=surveyPatchFromPayload(data,current);await ref.set(patch,{merge:true});if(patch.featuredOnHome||patch.isFeatured||patch.homeFeatured||patch.visibleOnHome)await preparePublicSurveyDocument(id,{featured:true,free:patch.isFree===true,actor:user}).catch(err=>console.warn('[adminUpdateSurvey] prepare public non-blocking',err?.message||err));await safeAudit({action:'adminUpdateSurvey',actorId:user.uid,actorType:user.role,companyId:current.companyId,entity:'survey',entityId:id,after:{title:patch.title,status:patch.status}});return {ok:true,id,updated:true};});
