exports.adminCreateForm=onCall(async req=>{const user=await adminCrudUser(req), data=deepCleanForFirestore(asObject(req.data?.payload||{},'payload'));assertCompanyScope(user,data);const ref=data.id?db.collection('forms').doc(data.id):db.collection('forms').doc();const payload=deepCleanForFirestore({...data,id:ref.id,companyId:data.companyId||user.companyId,organizationId:data.organizationId||data.companyId||user.companyId,createdAt:TS(),updatedAt:TS(),createdBy:user.uid,updatedBy:user.uid});await ref.set(payload,{merge:false});await safeAudit({action:'adminCreateForm',actorId:user.uid,actorType:user.role,companyId:payload.companyId,entity:'form',entityId:ref.id,after:{name:payload.name}});return {ok:true,id:ref.id,form:payload};});
exports.adminUpdateForm=onCall(async req=>{const user=await adminCrudUser(req), id=formIdFromData(req.data);if(!id)throw adminCrudError('invalid-argument','ID do formulário obrigatório.','form_id_required');const data=deepCleanForFirestore(asObject(req.data?.payload||{},'payload'));const ref=db.collection('forms').doc(id);const snap=await ref.get();if(!snap.exists)throw adminCrudError('not-found','Formulário não encontrado.','form_not_found');const current={id:snap.id,...snap.data()};assertCompanyScope(user,current);const surveys=await surveysForForm(id), responses=await responsesForSurveys(surveys.map(s=>s.id));const next={...current,...data};const breaking=hasBreakingFormChange(current,next);if((surveys.length||responses)&&breaking.breaking)throw adminCrudError('failed-precondition','Este formulário já está vinculado a pesquisas ou respostas. Crie uma nova versão para alterações estruturais.','form_breaking_change_requires_version',{action:'create_version',reason:breaking.reason});const patch=deepCleanForFirestore({...data,id:current.id,companyId:current.companyId,organizationId:current.organizationId,createdAt:current.createdAt,createdBy:current.createdBy,updatedAt:TS(),updatedBy:user.uid});await ref.set(patch,{merge:true});await safeAudit({action:'adminUpdateForm',actorId:user.uid,actorType:user.role,companyId:current.companyId,entity:'form',entityId:id,after:{name:patch.name}});return {ok:true,id,updated:true};});
exports.adminDeleteForm=onCall(async req=>{const user=await adminCrudUser(req), id=formIdFromData(req.data);if(!id)throw adminCrudError('invalid-argument','ID do formulário obrigatório.','form_id_required');const ref=db.collection('forms').doc(id);const snap=await ref.get();if(!snap.exists)throw adminCrudError('not-found','Formulário não encontrado.','form_not_found');const f={id:snap.id,...snap.data()};assertCompanyScope(user,f);const usage=await buildFormUsage(id,f);if(usage.activeSurveys.length)throw adminCrudError('failed-precondition','Este formulário está vinculado a pesquisas ativas. Encerre ou arquive as pesquisas antes de excluir.','form_linked_to_active_surveys',{formId:id,activeSurveys:usage.activeSurveys,activeSurveysCount:usage.activeSurveysCount,responsesCount:usage.responsesCount,suggestedActions:['close_surveys','archive_surveys','clone_form','create_form_version']});await ref.set(deepCleanForFirestore({status:'archived',archived:true,deleted:true,deletedAt:TS(),deletedBy:user.uid,updatedAt:TS(),updatedBy:user.uid}),{merge:true});await safeAudit({action:'adminDeleteForm',actorId:user.uid,actorType:user.role,companyId:f.companyId,entity:'form',entityId:id,after:{mode:'archived',responses:usage.responsesCount}});return {ok:true,mode:'archived',formId:id,removedFromActiveList:true,reason:usage.responsesCount?'form_has_responses':'safe_soft_delete'};});
exports.adminCloneForm=onCall(async req=>{const user=await adminCrudUser(req), formId=formIdFromData(req.data);if(!formId)throw adminCrudError('invalid-argument','ID do formulário obrigatório.','form_id_required');const changes=deepCleanForFirestore(asObject(req.data?.changes||{},'changes'));const snap=await db.collection('forms').doc(formId).get();if(!snap.exists)throw adminCrudError('not-found','Formulário original não encontrado.','form_not_found');const original={id:snap.id,...snap.data()};assertCompanyScope(user,original);const id=`${original.id}_clone_${Date.now()}`;const payload=deepCleanForFirestore({...original,...changes,id,sourceFormId:original.id,previousVersionId:original.id,status:changes.status||'draft',createdAt:TS(),updatedAt:TS(),createdBy:user.uid,updatedBy:user.uid});await db.collection('forms').doc(id).set(payload,{merge:false});await safeAudit({action:'adminCloneForm',actorId:user.uid,actorType:user.role,companyId:payload.companyId,entity:'form',entityId:id,after:{sourceFormId:formId}});return {ok:true,id,form:payload};});
exports.adminCreateFormVersion=onCall(async req=>{const user=await adminCrudUser(req), formId=formIdFromData(req.data);if(!formId)throw adminCrudError('invalid-argument','ID do formulário obrigatório.','form_id_required');const changes=deepCleanForFirestore(asObject(req.data?.changes||{},'changes'));const snap=await db.collection('forms').doc(formId).get();if(!snap.exists)throw adminCrudError('not-found','Formulário original não encontrado.','form_not_found');const original={id:snap.id,...snap.data()};assertCompanyScope(user,original);const version=Number(original.version||1)+1;const id=formVersionId(original.id,version);const payload=deepCleanForFirestore({...original,...changes,id,sourceFormId:original.sourceFormId||original.id,previousVersionId:original.id,version,status:changes.status||'draft',createdAt:TS(),updatedAt:TS(),createdBy:user.uid,updatedBy:user.uid});await db.collection('forms').doc(id).set(payload,{merge:false});await safeAudit({action:'adminCreateFormVersion',actorId:user.uid,actorType:user.role,companyId:payload.companyId,entity:'form',entityId:id,after:{sourceFormId:formId,version}});return {ok:true,id,form:payload};});
exports.repairOfficialFormDocument=onCall(async req=>{const user=await authedUser(req);if(!['admin_valora','consultor_valora'].includes(user.role))throw adminCrudError('permission-denied','Sem permissão para reparar documento oficial.','official_repair_role_required');const beforeSnap=await db.collection('forms').doc(OFFICIAL_FREE_SURVEY_IDS.formId).get();const before=beforeSnap.exists?beforeSnap.data():{};const company=deepCleanForFirestore({...officialCompanyPayload(),updatedAt:TS()});const form=deepCleanForFirestore({...officialFreeSurveyForm(),...before,id:OFFICIAL_FREE_SURVEY_IDS.formId,isGlobal:true,companyId:'valora-oficial',organizationId:'valora-oficial',status:'active',updatedAt:TS()});const token=createToken(24);const survey=deepCleanForFirestore({id:'official_free_survey',companyId:'valora-oficial',organizationId:'valora-oficial',formId:'form_valora_insight_oficial',title:'Diagnóstico Gratuito Valora Insight™',description:'Responda gratuitamente e receba uma análise inicial sobre a maturidade da sua empresa.',lgpdTitle:DEFAULT_LGPD_TITLE,lgpdText:DEFAULT_LGPD_TEXT,lgpdCheckbox:DEFAULT_LGPD_CHECKBOX,lgpdCardText:DEFAULT_LGPD_CARD,deleted:false,archived:false,status:'published',visibility:'public',featuredOnHome:false,isFeatured:false,homeFeatured:false,visibleOnHome:false,isFree:true,planId:'free',requireIdentification:true,lgpdRequired:true,allowRepeat:true,anonymous:false,showResult:true,revoked:false,revokedAt:null,publicToken:before.publicToken||token,token:before.token||token,tokenHash:before.tokenHash||sha256(token),startsAt:before.startsAt||new Date().toISOString(),expiresAt:'2099-12-31T23:59:59.000Z',updatedAt:TS()});const batch=db.batch();batch.set(db.collection('organizations').doc('valora-oficial'),company,{merge:true});batch.set(db.collection('companies').doc('valora-oficial'),company,{merge:true});batch.set(db.collection('forms').doc('form_valora_insight_oficial'),form,{merge:true});batch.set(db.collection('surveys').doc('official_free_survey'),survey,{merge:true});await batch.commit();const {tokenHash,...safeSurvey}=survey;await safeAudit({action:'repairOfficialFormDocument',actorId:user.uid,actorType:user.role,companyId:'valora-oficial',entity:'form',entityId:OFFICIAL_FREE_SURVEY_IDS.formId});return {ok:true,before:deepCleanForFirestore(before),after:{form,survey:safeSurvey,company}};});
